import{_ as a,o as t,c as s,a3 as r}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"77. Special Disaster Leave","description":"","frontmatter":{"title":"77. Special Disaster Leave","eba":"Allied Health Professionals 2021-2026","topics":["leave","preliminary"]},"headers":[],"relativePath":"ebas/allied-health/leave/77-special-disaster-leave.md","filePath":"ebas/allied-health/leave/77-special-disaster-leave.md"}'),i={name:"ebas/allied-health/leave/77-special-disaster-leave.md"};function o(l,e,n,p,d,c){return t(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="_77-special-disaster-leave" tabindex="-1">77. Special Disaster Leave <a class="header-anchor" href="#_77-special-disaster-leave" aria-label="Permalink to &quot;77. Special Disaster Leave&quot;">​</a></h1><p>Note: In this clause 77, ‘up to’ refers to the total amount of paid special disaster leave per calendar year an Employee is entitled to access whilst they qualify and does not confer a discretion on the Employer to provide fewer than three (3) days leave. That is where the Employee qualifies in accordance with this clause 77 for three (3) days paid special disaster leave, the Employer must provide them with three (3) days paid special disaster leave.</p><p><strong>77.1</strong> An Employee is entitled to paid special disaster leave of up to three (3) days per calendar year. An Employee may take special disaster leave where:</p><p><strong>(a)</strong> the Employee is a full time or part time Employee;</p><p><strong>(b)</strong> Personal Leave is not available either because the Employee has exhausted the accrual or the circumstance does not qualify for Personal Leave; and</p><p><strong>(c)</strong> the Employee is unable to attend work due to a disaster (such as fire or flood) where:</p><p><strong>(i)</strong> the Employee&#39;s residence is damaged or under imminent threat of major damage;</p><p><strong>(ii)</strong> the lives or safety of their immediate family or household members are threatened; or</p><p><strong>(iii)</strong> there is a formal closure, flooding or other unusual danger on the road(s) which is the Employee&#39;s normal travel route to work and no alternative practicable travel route is available.</p><p><strong>77.2</strong> Special disaster leave is non-cumulative.</p><p>Plain language terms: disaster leave, flood, bushfire.</p>',11)])])}const u=a(i,[["render",o]]);export{m as __pageData,u as default};
